var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"저 사람의 이름은 라비. 당신의 아버지입니다.","JPN":"あの人の名前はラビ。あなたの父親です。","ENG":"That person's name is Ravi. He is your father.","TWN":"那個人的名字是拉維，他就是你的爸爸。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"라비…… 아버지…….","JPN":"ラビ……お父さん……","ENG":"Ravi... My father...","TWN":"拉維……我的爸爸……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아버지의 기억이 여기 투영되었다는 것은…… 아버지 역시…….","JPN":"お父さんの記憶がここに投影されたということは……お父さんも……","ENG":"Seeing a projection of my father's memory here... can only mean that...","TWN":"爸爸的記憶被投影在這裡……那爸爸他也……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"그 역겨운 잔재주를 이용해 잘도 모습을 숨기고 계셨군요. 찾느라 고생 좀 했습니다.","JPN":"そのむかつく小細工でよくも姿を暗ましていましたね。探すのに苦労しました。","ENG":"So you have been using that vile trick to hide from us. It took us quite the trouble to find you.","TWN":"可真夠會躲的，多虧了你那些噁心的小把戲，我找你們可費了不少功夫。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"역시…… 들켜버렸네요.","JPN":"やはり……バレてしまいましたか。","ENG":"So... we've been caught.","TWN":"果然……還是被發現了。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아, 아버지…….","JPN":"お、お父さん……","ENG":"F-father...","TWN":"爸，爸爸……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"아샤! 저 자는 당신이 생각하는 아버지가 아닙니다!","JPN":"アーシャ！　あれはあなたが探していた父親ではありません！","ENG":"Asha! That man is not the father you think he is!","TWN":"阿莎！那個人不是你爸爸！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"아샤! 정신 차리세요!","JPN":"アーシャ！　しっかりしてください！","ENG":"Asha! Come to your senses!","TWN":"阿莎！清醒點！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L25_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RINGING"},{"id":"L28_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"무슨 짓을 한 거죠?","JPN":"何をしたのですか？","ENG":"What did you do?","TWN":"你對她做了什麼？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"저 자는 아디트야를 따르던 불순물입니다.","JPN":"その者はアーディティヤに従っていた不純物です。","ENG":"She is an impurity that used to follow Aditya.","TWN":"她只不過是追隨阿迪亞的雜質。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"아디트야를 꾀어내기 위해 삼켰지만, 흥미로운 걸 갖고 있더군요.","JPN":"アーディティヤをおびき寄せるために飲み込みましたが、どうやら興味深いものを持っているようで。","ENG":"I had swallowed her to lure Aditya here, but it seems that she had something interesting in her possession.","TWN":"吞下她是為了引誘阿迪亞來這裡，不過我現在覺得她很有趣。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"그래서, 불순물에게 아주 작은 기회를 주기로 했습니다.","JPN":"それで、不純物にほんの少しのチャンスを与えることにしました。","ENG":"So, I have decided to give the impurity a very small chance.","TWN":"所以我決定給這個雜質一個小小的機會。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"저 자는 지금 저와 함께 과거를 돌아보며 선택의 기로에 놓여 있겠죠.","JPN":"その者は今私とともに過去を振り返りながら、選択の岐路にいることでしょう。","ENG":"She will now probably be faced with a choice while looking back on the past with me.","TWN":"她現在應該是和我一起沉浸在過去的記憶裡，站在選擇的十字路口。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"우리를 받아들이고 더 나아갈지, 아니면 영원한 거짓 속에서 잠들지.","JPN":"私たちを受け入れて前に進むか、それとも永遠たる偽りの中で眠りにつくか。","ENG":"Whether she will accept us and move on, or sleep in eternal lies.","TWN":"是選擇接受然後繼續前進，還是一直沉睡在永恆的謊言裡……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"더 이상 그분의 명예를 더럽히지 마시죠.","JPN":"もうあの人の名誉を汚すのはやめて。","ENG":"Do not tarnish his honor any further.","TWN":"不要汙名化他了。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"당신이 무슨 짓을 하더라도, 당신은 라비가 될 수 없습니다.","JPN":"あなたが何をしようとも、あなたはラビにはなれません。","ENG":"Whatever you do, you will never become Ravi.","TWN":"無論你做什麼，你都無法成為拉維。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"제가 라비입니다. 라비의 모습, 라비의 기억, 라비의 모든 것을 갖고 있는 제가요.","JPN":"私がラビなのです。ラビの姿、ラビの記憶、ラビのすべてを持っている私こそが。","ENG":"I am Ravi. I have his appearance, his memories, and everything else.","TWN":"我就是拉維。我擁有拉維的外貌、拉維的記憶，以及拉維的一切。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"너같이 미지근하고, 속내가 복잡한 녀석은 불꽃의 이름을 받을 자격이 없다.","JPN":"君のような生ぬるく、いけ好かない下心を持っているやつに炎の名を受け継ぐ資格などない。","ENG":"Someone who is as lukewarm and complicated as you does not deserve the name of the flame.","TWN":"像你這樣優柔寡斷、心思複雜的傢伙，不配擁有火焰之名。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"넌 아합이다. 너에게 딱 어울리는 이름이지.","JPN":"君はアハブだ。それが君に相応しい名前だ。","ENG":"You are Ahab. That's a name that befits you.","TWN":"你是亞哈，這個名字非常適合你。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"너는 그자처럼 불꽃을 피우지 못해. 나는 그 이름을 허락하지 않는다.","JPN":"君は彼のような炎を起こすことはできない。私はその名前を許可しない。","ENG":"You cannot ignite a flame like him, and I have never allowed that name to you.","TWN":"你無法像他那樣燃起火焰，我不允許你使用那個名字。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"저는 아합이 아닙니다…… 우리와 함께 해야 할 당신이 그런 말을 하다니…… 실망이군요.","JPN":"私はアハブではありません……私たちと一つになるべきあなたがそんなことを口にするとは……残念です。","ENG":"I am not Ahab... Hearing you say that when you should be joining us is... heartbreaking.","TWN":"我不是亞哈……應該和我們站在一起的你，竟然說出這種話……真讓人失望。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"아합……?","JPN":"アハブ……？","ENG":"Ahab...?","TWN":"亞哈……？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"잡담은 됐습니다. 잠깐 거기 서서 불순물이 우리와 함께 완전해지는 걸 지켜보시죠.","JPN":"雑談はここまでです。しばらくそこに立って、不純物が私たちとともに完全となる姿をとくとご覧ください。","ENG":"This conversation is over. Stand there for a moment and witness the impurity become one with us.","TWN":"閒聊到此為止。站在那裡，好好看著雜質是如何與我們一起變得完美的吧。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"큭……! 움직일 수가……!","JPN":"くっ……！　動けない……！","ENG":"Kgh... I can't move...!","TWN":"咳……！沒辦法動……！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_BOW"},{"id":"L14_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"저 자의 선택이, 나를 아합이 아닌 라비로 만들어줄 것입니다.","JPN":"その者の選択が、私をアハブではなくラビへと変えてくれることでしょう。","ENG":"Her choice will turn me into Ravi and not Ahab.","TWN":"那個人的選擇，會讓我成為拉維，而非亞哈……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"여긴…… ","JPN":"ここは…… ","ENG":"This is...?","TWN":"這裡是……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"어머니가 돌아가셨던…….","JPN":"お母さんが亡くなった……","ENG":"It's the place where my mother passed away...","TWN":"媽媽去世前住的地方……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MOM_VARUNA_NPC_ASHA","text":{"KOREA":"오늘은 배급이 나왔더구나.","JPN":"今日は配給をもらえるのよ。","ENG":"Rations came in today.","TWN":"今天有發配給喔。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOM_VARUNA_NPC_ASHA","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"엄마? 어, 엄마는 분명…….","JPN":"え？　お母さん？　お母さんは確か……","ENG":"Mom? B-but you are...","TWN":"媽媽？可是，媽媽明明已經……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOM_VARUNA_NPC_ASHA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"MOM_VARUNA_NPC_ASHA","text":{"KOREA":"곧 있으면 아빠가 온다고 하니까, 얼른 엄마 좀 도와줘.","JPN":"もうすぐお父さんが帰ってくるらしいから、早く手伝ってちょうだい。","ENG":"Dad will soon be home, so could you help me?","TWN":"爸爸就要回來了，你快來幫幫媽媽。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOM_VARUNA_NPC_ASHA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"……아빠가?\xA0","JPN":"……お父さんが？\xA0","ENG":"...Dad?\xA0","TWN":"……爸爸？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOM_VARUNA_NPC_ASHA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"내가 지금 꿈을 꾸고 있는 건가?","JPN":"私、今夢を見てる？","ENG":"Am I dreaming right now?","TWN":"難道我現在在做夢嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOM_VARUNA_NPC_ASHA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"MOM_VARUNA_NPC_ASHA","text":{"KOREA":"아까부터 뭘 자꾸 혼자 중얼거리는 거니? 안 도와줄 거야?","JPN":"さっきから何をぶつぶつ言ってるの？　手伝ってくれないの？","ENG":"What are you muttering to yourself about? Aren't you going to help?","TWN":"你這孩子在那嘀咕什麼？還不快來過來幫忙？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOM_VARUNA_NPC_ASHA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아, 아니에요! 지금 가요!","JPN":"あ、今行く！","ENG":"Y-yes! Coming!","TWN":"沒，沒什麼！現在就來！"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MOM_VARUNA_NPC_ASHA","text":{"KOREA":"장성한 네 모습을 보고 싶다고 서두르던 그 목소리가 어찌나 웃기던지.","JPN":"成長したあなたの姿が見たいって急かす声が本当におかしかったのよ。","ENG":"It was funny to hear him be excited to see how much you've grown.","TWN":"爸爸很想見到你呢，想到他心急的語調就覺得好笑。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOM_VARUNA_NPC_ASHA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"MOM_VARUNA_NPC_ASHA","text":{"KOREA":"아샤, 아빠가 오면 낯 가리지 말고.","JPN":"アーシャ、お父さんが来たら人見知りしないことね。","ENG":"Asha, don't be shy when Dad gets home, okay?","TWN":"阿莎，看到爸爸不要害羞喔？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOM_VARUNA_NPC_ASHA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"엄마도 참! 내가 언제 낯 가리는 거 봤어요?!","JPN":"お母さんったら！　私が人見知りするわけないでしょう！？","ENG":"Oh, Mom! When was I ever shy?!","TWN":"真是的，媽媽！我什麼時候怕生過？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOM_VARUNA_NPC_ASHA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"MOM_VARUNA_NPC_ASHA","text":{"KOREA":"하하. 그랬지.","JPN":"はは。そうだったわね。","ENG":"Haha. You're right.","TWN":"呵呵，也對。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOM_VARUNA_NPC_ASHA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"MOM_VARUNA_NPC_ASHA","text":{"KOREA":"아빠가 왔나 보다. 어서 맞이해드려.\xA0","JPN":"お父さんが来たみたい。早くお迎えして。\xA0","ENG":"I think Dad's home. Go welcome him home.\xA0","TWN":"應該是爸爸吧，快去開門。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOM_VARUNA_NPC_ASHA","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"네! 나가요!","JPN":"はーい！　今行きます！","ENG":"Okay! Coming!","TWN":"來囉！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아빠……?","JPN":"お父さん……？","ENG":"Dad...?","TWN":"爸爸？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아빠 맞죠? 보고 싶었어요.","JPN":"お父さんですよね？　会いたかったです。","ENG":"It's you, right? I missed you so much.","TWN":"爸爸，是爸爸嗎？我好想你喔。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"나도 마찬가지란다. 딸.","JPN":"俺もだ。我が娘。","ENG":"I missed you too, Asha.","TWN":"我也是，女兒。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"얼른 들어가자. 할 얘기가 많아.","JPN":"早く中に入ろう。話したいことがたくさんあるんだ。","ENG":"Let's go inside. There is a lot to talk about.","TWN":"快進去吧。我有很多話要說。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"군인이라고요? 그건 너무 위험하지 않나요? 게다가 침식체들을 잡고 있다니…….","JPN":"軍人だなんて、危険すぎるんじゃないですか？　しかも侵食体をやっつけているなんて……","ENG":"You're a soldier? Isn't that dangerous? And you're also hunting C.O.s...?","TWN":"軍人嗎？那是不是很危險？而且還要對付侵蝕體……"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"세상을 위한 일이야. 내 한평생 이를 후회한 적은 없어.","JPN":"世界のためだ。今までこの仕事をしていて後悔したことなどはない。","ENG":"It's for the good of the world. I've never regretted it once.","TWN":"爸爸是為世界而戰，我從未為此後悔過。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"아빠 없이도 잘 자라주었구나. 그간 많이 힘들지는 않았니?","JPN":"お父さんがいなくても、立派に成長したな。今までつらくはなかったか？","ENG":"I'm relieved to see that you grew up well even without me. Wasn't it rough?","TWN":"爸爸不在的這段時間，女兒長大不少呢。那段時間很辛苦吧？"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"힘들었죠.","JPN":"つらかったです。","ENG":"It was.","TWN":"超辛苦的。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"어린 나이에 어떻게든 이 지긋지긋한 곳을 나가고 싶어서","JPN":"幼いころから、何とかこのうんざりとしたところから出たくて。","ENG":"I wanted to get out of this place even though I was young","TWN":"小時候的我，只想儘早離開這個令我討厭的地方。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"엄마는 또 어떻고요? 어린 저를 먹여 살리기 위해서 일하시다가…….","JPN":"お母さんもそうでした。幼い私を養うために仕事して……","ENG":"What about Mom? She was working so hard to feed me...","TWN":"媽媽呢？她每天拼命工作要養活我……"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"그로니아 난민촌에서 대규모 이상 현상이 발생하여 수많은 사상자가…….","JPN":"グロニアの難民キャンプで大規模の異常現象が発生し、多数の死傷者が……","ENG":"Countless casualties arose when a large-scale abnormal phenomenon occurred in a Gronian refugee camp...","TWN":"格羅尼亞難民營發生大規模異常現象，出現大量傷亡……"},"stage":{"bg":"HARMONY_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"방금 뭔가…….","JPN":"今、何か……","ENG":"Something just...","TWN":"剛才那是……"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"미안하구나. 딸. 그럼 모처럼 만났는데, 아빠랑 밖에 나가지 않을래?","JPN":"苦労をかけたな、アーシャ。そうだ、せっかく会ったことだし、お父さんと出かけないか？","ENG":"I'm sorry, child. It's been a long time since we last met. Would you like to go out with your dad?","TWN":"對不起，女兒，好不容易相聚，要不要和爸爸一起出去走走？"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"좋아요. 아빠.","JPN":"いいですよ。お父さん。","ENG":"Okay, Dad.","TWN":"好的，爸爸。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"이곳은 여전히 평화롭구나.","JPN":"ここは相変わらず平和だな。","ENG":"This place sure is as peaceful as ever.","TWN":"這裡依然很平靜呢。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"시간 문제죠. 그로니아에 퍼져 있는 침식파 밀도가 점점 높아지고 있어요.","JPN":"時間の問題ですよ。グロニアに広がっている侵食波の密度がどんどん高くなってるんですから。","ENG":"It's only a matter of time. The Corruption ray density spreading across Gronia is rising.","TWN":"只不過是時間問題而已……格羅尼亞的侵蝕波密度正在逐漸增加。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"곧 이 난민촌도…….","JPN":"もうすぐこの難民キャンプも……","ENG":"Soon, even this refugee camp will...","TWN":"很快這個難民營也會……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"그렇다면 아빠와 함께 떠나지 않을래?","JPN":"なら、お父さんと一緒にここを出ないか？","ENG":"Then, how about you leave with me?","TWN":"那，要不要和爸爸一起離開？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L39_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"함께…… 떠난다고요?","JPN":"一緒に……出る？","ENG":"Leave... with you?","TWN":"一起……離開嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"그래. 아빠와 함께 세상을 지키기 위해 떠나는 거야.","JPN":"ああ。お父さんと一緒に世界を守るために旅立つんだ。","ENG":"Yes. You'll join me in saving the world.","TWN":"是的，和爸爸一起離開這裡，去守護這個世界。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"그곳에선 가난하게 지낼 일도, 혼자가 되어 외로울 일도, 소중한 사람이 죽을 일도 없단다.","JPN":"そこでは貧乏することも、一人になって寂しい思いをすることも、大切な人が死ぬこともない。","ENG":"Over there, you won't have to worry about poverty, being alone, or seeing your loved ones die.","TWN":"在那裡沒有貧窮，不會孤單寂寞，也不會有重要的人去世。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"어때? 네가 원하는 삶 아니니?","JPN":"どうだ？　お前が望んでいた人生だろう？","ENG":"What do you think? Isn't it the life you always wanted?","TWN":"怎麼樣？這不是你想要的生活嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"내가 원하는…… 삶…….","JPN":"私が望んでいた……人生……","ENG":"The life... I always wanted...","TWN":"我想要的……生活……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"더 많은 곳을 구경시켜주고, 더 많은 경험을 하게 해주고 싶었는데…….","JPN":"もっとたくさんの場所に連れていき、たくさんのことを経験させてやりたかったが……","ENG":"I wanted to show you more places and let you experience new things...","TWN":"我本想帶著那個失去媽媽的孩子去更多地方看看，讓她有更多的經歷……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"마지막에 얼굴이라도 보고 와서 다행이야. 그 아이가 날 기억해줄진 모르겠지만.","JPN":"最後に顔を見てきてよかった。あの子が俺のことを覚えてくれるかはわからないが。","ENG":"But at least I got to see her face for one last time. Even if she might not be able to remember me.","TWN":"不過幸好有跟她見到最後一面。雖然不知道她是否會記得我。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"네. 저는 아버지와 함께 여행을 가고 싶었어요.","JPN":"はい。私お父さんと一緒に旅行したかったんです。","ENG":"Yes. I wanted to travel with my father.","TWN":"我，我想和爸爸一起去旅行！"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아버지와 여행을 다니고 싶어서 각 국가의 지형과 관광지를 달달 외웠죠.","JPN":"お父さんと旅行したくて、色んな国の地形と観光地まで暗記しましたよ。","ENG":"So much so that I memorized each country's geography and tourist attractions.","TWN":"為了這個夢想，我還背熟每個國家的地形和旅遊景點呢。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"언젠가 돌아올 아버지의 손을 잡아끌고 그동안 보지 못했던 곳들을 보고 싶어서.","JPN":"いつか帰ってくるお父さんと手を繋いで、今まで見ることのできなかった場所を見たくて。","ENG":"I hoped that my father would return so I could hold his hand and go to places I've never been.","TWN":"想著總有一天能牽著爸爸的手，去看看那些一直未曾見過的地方。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"그래. 이제는 함께할 수 있단다.","JPN":"ああ。今なら一緒にできる。","ENG":"Yes. And now, you can.","TWN":"太好了，現在可以和爸爸可以一起去了。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"그 전에, 내가 너에게 맡겼던 물건을 줄 수 있겠니?","JPN":"その前に、俺がお前に預けたものを返してくれるか？","ENG":"Before that, could you give back the thing I left you with?","TWN":"但在那之前，能把我之前交給你的東西給我嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"물건…… 이요?","JPN":"預けたもの……ですか？","ENG":"The... thing?","TWN":"給我的東西……嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"<color=#ff3636>그게 없으면 아빠는 아빠가 아니게 되거든.</color>","JPN":"<color=#ff3636>それがないと、お父さんはお父さんでいられなくなる。</color>","ENG":"<color=#ff3636>Without it, Dad can't be himself.</color>","TWN":"<color=#ff3636>沒有那個，爸爸就不是爸爸了。</color>"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"우리가 함께 떠나기 위해선 그 물건이 꼭 필요해.","JPN":"俺たちが一緒に旅に出るためには、それが必ず必要なんだ。","ENG":"We need it so we can go together.","TWN":"要一起出發的話，那件東西是必需的。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"우리는 태양의 빛을 좇아야 하니까.","JPN":"俺たちは太陽の光を追わなければならないからな。","ENG":"Because we must chase the light of the sun.","TWN":"我們必須追隨太陽的光芒。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"……!","JPN":"……！","ENG":"...!","TWN":"……！"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"그로니아 난민촌에서 대규모 이상 현상이 발생하여 수많은 사상자가 발생했습니다.","JPN":"グロニアの難民キャンプで大規模の異常現象が発生し、多数の死傷者が発生しました。","ENG":"Countless casualties arose when a large-scale abnormal phenomenon occurred in a Gronian refugee camp.","TWN":"最新消息，格羅尼亞難民營發生大規模異常現象，出現大量傷亡。"},"stage":{"bg":"HARMONY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"피해 규모는 알 수 없으며, 보호받지 못하는 난민들의 수가 많아 피해는 극심해질 것으로…….\xA0","JPN":"被害の規模は不明で、保護されていない難民の数が多いため甚大な被害になると……\xA0","ENG":"The extent of the damage is still unknown, but the damage is expected to be severe due to the large number of unprotected refugees...\xA0","TWN":"無法確定受害規模，因未受保護的難民數量眾多，預計損失將會非常嚴重……"},"stage":{"bg":"HARMONY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"엄마!!!! 엄마가 저기 깔려 있어요!! 엄마 좀 구해주세요!!","JPN":"お母さんが！！！！　お母さんがあそこで下敷きになってるんです！！　お母さんを助けてください！！","ENG":"Mom!! My mom's under there!! Someone save her!!","TWN":"媽媽！！！！媽媽被壓在那底下！！誰來救救媽媽！！"},"stage":{"bg":"HARMONY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"괴물들이 엄마한테 다가가고 있다고요!!! 제가 아니라 엄마를 구해달라고요!!!","JPN":"化け物たちがお母さんに近づいてるんですよ！！！　私よりも、お母さんを助けてください！！！","ENG":"The monsters are getting close to her!!! Not me! Save my mom!!!","TWN":"怪物正在靠近媽媽！！！你們去救媽媽，不要管我！！！"},"stage":{"bg":"HARMONY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"엄마아아악!!!!","JPN":"お母さん！！！！","ENG":"MOMMM!!!","TWN":"媽媽！！！！"},"stage":{"bg":"HARMONY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"narration","speaker":null,"text":{"KOREA":"시체조차 찾지 못한 우리 엄마.","JPN":"死体すら見つけられなかったお母さん。","ENG":"Her body was never found.","TWN":"最後我連媽媽的屍體都沒有找到。"},"stage":{"bg":"CAMP_01","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"narration","speaker":null,"text":{"KOREA":"돈이 없단 이유로 비석 하나 세우지 못한 채, 그렇게 보낸 우리 엄마.","JPN":"お金がないという理由で石碑も建てられないまま、お別れをしたお母さん。","ENG":"I had to send her off without even leaving a gravestone because I didn't have any money.","TWN":"因為沒有錢，連一塊墓碑都沒有，就這樣送走媽媽。"},"stage":{"bg":"CAMP_01","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"narration","speaker":null,"text":{"KOREA":"위로금 몇 푼만 간신히 챙긴 채 나는 세상을 떠돌았다.","JPN":"たった少しの支援金をもらった私は、世界を回った。","ENG":"Then, I roamed the world with the little compensation that they gave me.","TWN":"最後，我帶著僅有的一點撫慰金，開始四處流浪。"},"stage":{"bg":"CAMP_01","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"narration","speaker":null,"text":{"KOREA":"언젠가 모두와 함께하고 싶어 달달 외웠던 세계의 역사와 지형을 돌아보면서.","JPN":"いつかみんなで一緒に行きたくて暗記した世界の歴史と地形を巡りながら。","ENG":"I traveled to places that I had once memorized in hopes of going there together.","TWN":"那些我曾經希望一起去的地方，現在由我獨自走過。"},"stage":{"bg":"CAMP_01","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_01","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"조금만…… 더 빨리 이러지 그랬어.","JPN":"もうちょっと早く……こうしていればよかったのに。","ENG":"If only... you came to me sooner.","TWN":"為什麼……不再早一點。"},"stage":{"bg":"CAMP_01","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"……?","JPN":"……？","ENG":"...?","TWN":"……？"},"stage":{"bg":"CAMP_01","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그랬으면…… 적어도 당신이 내 아버지라는 걸 알고 속아 넘어갔을 텐데.","JPN":"そしたら……少なくともあなたが私のお父さんだと信じて疑わなかったわ。","ENG":"Then... I would've at least been fooled into thinking that you were my father.","TWN":"如果那樣的話……至少我會相信你是我爸爸。"},"stage":{"bg":"CAMP_01","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L46_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"그게 무슨…… 소리니?","JPN":"それはどういう……ことだ？","ENG":"What... do you mean by that?","TWN":"你在……說什麼？"},"stage":{"bg":"CAMP_01","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"특히 너에게 미안하군. 라비. 딸과 둘이서 여행을 다니고 있지 않았나?","JPN":"特に君には申し訳ないと思っている。ラビ。娘と二人で旅をしているのだろう？","ENG":"Especially to you, Ravi. Didn't you say you wanted to go traveling with your daughter?","TWN":"特別是你，拉維。你還在和女兒一起旅行……"},"stage":{"bg":"CITY_DESERT","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"나는 혼자서 세계를 떠돌아다닌 게 아니었어.","JPN":"私は一人で世界を回ってたわけじゃなかった。","ENG":"I didn't roam the world on my own.","TWN":"我不是一個人在世界各地漂泊。"},"stage":{"bg":"CAMP_01","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아버지는…… 어머니를 잃은 나를 데리고 세계 여기저기를 여행하셨다고 했지.","JPN":"お父さんは……お母さんが亡くなった後、私を連れて、世界中のあちこちを旅行したって言ってた。","ENG":"My father... said that he took me all over the world after Mom had passed.","TWN":"爸爸……帶著失去媽媽的我，走遍世界各地。"},"stage":{"bg":"CAMP_01","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"지금 생각해보면 이상한 게 한둘이 아니었는데, 왜 의심하지 않았을까?","JPN":"今思うとおかしなところがたくさんあったのに、どうして疑わなかったんだろう？","ENG":"Now thinking back on it, there were quite a few strange things about it. I wonder why I didn't suspect any.","TWN":"現在想想，奇怪的事情不止一兩件，為什麼以前從沒有懷疑呢？"},"stage":{"bg":"CAMP_01","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"결국 내 기억도…… 바뀌었던 거지. 그 빌어먹을 침식체로 인해서.","JPN":"結局私の記憶も……変わったのよ。あの侵食体のせいで。","ENG":"In the end... even my memory was altered. Due to that damned C.O.","TWN":"我的記憶……因為那個該死的侵蝕體，最後也被改變了。"},"stage":{"bg":"CAMP_01","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"진짜 아버지라면…… 내 이름을 말해 봐.","JPN":"本物のお父さんなら……私の名前を呼んでみなさいよ。","ENG":"If you really are my father... then say my name.","TWN":"如果你真的是我爸爸……那就說出我的名字吧。"},"stage":{"bg":"CITY_DESERT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"That's...","TWN":"名字……"},"stage":{"bg":"CITY_DESERT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"역시 대답할 수 없겠지. 애초에 너에게 있어선, 내 이름따위는 중요한 게 아니었을 테니.","JPN":"呼べるはずないもんね。そもそもあなたにとって、私の名前なんて重要じゃなかったんだから。","ENG":"So, you can't. Because my name was never important to you in the first place.","TWN":"你果然無法回答。對你來說，我的名字本來就不重要吧？"},"stage":{"bg":"CITY_DESERT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"네가 나에게 원했던 건 단지, 내가 갖고 있던 아버지의 유품인 나침반뿐이잖아?","JPN":"あなたが欲しかったのは、私が持っていたお父さんの遺品……羅針盤だけだったんでしょ？","ENG":"The only thing you wanted from me was the compass my father left me, isn't it?","TWN":"你想要的不過是我爸爸留下的遺物，就是那個指南針，不是嗎？"},"stage":{"bg":"CITY_DESERT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"네가 아버지에 대해 알 수 있는 건 여태 싸워왔던 아버지의 기억뿐.","JPN":"あなたがお父さんについて知ってるのは、今まで戦ってきたお父さんの記憶だけよ。","ENG":"The only things you know about him are the memories of his fights.","TWN":"你對爸爸的了解，只能從你們一直以來戰鬥的記憶中得知。"},"stage":{"bg":"CITY_DESERT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"……소멸했군. 원본을 흡수했다면 이렇게 불안정한 모습은 아니었을 텐데.","JPN":"……消滅したな。オリジナルを吸収していたのなら、ここまで不安定な姿ではなかったはずだ。","ENG":"...She's gone. If she had absorbed her original, she wouldn't have been this unstable.","TWN":"……消失了。如果已經吸收掉本體的話，應該不至於會如此不穩定。"},"stage":{"bg":"CITY_DESERT","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"워, 원본을 흡수해요? 그림자가요?","JPN":"お、オリジナルを吸収するって、シャドウがですか？","ENG":"A-absorb her original? The Shadow?","TWN":"什麼，暗影會吸收本體嗎？"},"stage":{"bg":"CITY_DESERT","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"도플갱어 타입 그림자는 완전해지기 위해 원본이 되는 인간을 흡수하고 싶어 한다.","JPN":"ドッペルシャドウは己を完全なものとするために、オリジナルとなる人間を吸収したがる。","ENG":"Doppelganger-type Shadows want to absorb their original human to become whole.","TWN":"聽說二重身暗影為了要變得完整，會試圖吸收本體。 "},"stage":{"bg":"CITY_DESERT","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그렇게 된다면 힘, 기억, 원본에 해당하는 모든 것을 자기 것으로 만들 수 있으니까.","JPN":"そうすれば力、記憶、オリジナルが持っているもの全てを自分のものにできるからな。","ENG":"Because by doing so, they will make the original's strength and memories their own.","TWN":"一旦成功，就能將力量、記憶和屬於本體的一切據為己有。"},"stage":{"bg":"CITY_DESERT","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"너, 아버지를 흡수하지 못한 거지?\xA0","JPN":"あなた、お父さんを吸収できなかったんでしょ？\xA0","ENG":"You couldn't absorb him, could you?\xA0","TWN":"你，還沒能吸收本體吧？"},"stage":{"bg":"COUNTRYROAD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"……!","JPN":"……！","ENG":"...!","TWN":"……！"},"stage":{"bg":"COUNTRYROAD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"당신이 원했던 이 나침반은 절대 주지 않을 거야.","JPN":"あなたが欲しがるこの羅針盤は絶対あげない。","ENG":"I'm never giving you the compass.","TWN":"你想要的指南針，我絕對不會給你。"},"stage":{"bg":"COUNTRYROAD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아버지를 욕보이는 침식체에게 하나뿐인 유품을 줄 수는 없거든.","JPN":"お父さんを侮辱する侵食体に、たった一つしかない遺品をあげるわけにはいかないから。","ENG":"I am not giving my keepsake to a C.O. that dishonors my father.","TWN":"我是不會把爸爸唯一的遺物，交給玷汙他的侵蝕體的。"},"stage":{"bg":"COUNTRYROAD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"이 물건이 있어야 앞으로의 계획에 진전이 있는 모양이지?","JPN":"これがなかったら、これからの計画を進められないんでしょ？","ENG":"Seems like you need it for your plans, don't you?","TWN":"有這個東西，你接下來的計畫才能有所進展吧？"},"stage":{"bg":"COUNTRYROAD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"하, 하하. 그래. 그래서 나를 삼켰던 거였어.","JPN":"ハ、ハハ。そう。それで私を飲み込んだのよね。","ENG":"Ha, haha. Yeah. That's why you swallowed me.","TWN":"呵，呵呵。沒錯，所以你才把我吞進肚子裡。"},"stage":{"bg":"COUNTRYROAD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그 추악한 속내를 모두 알았으니…… 이젠 끝이야. 침식체.","JPN":"その醜悪な下心はすべて把握したから……もう終わりよ。侵食体。","ENG":"But since you have shown your ugly true colors... it's over, C.O.","TWN":"我已經看透你醜陋的內心……都結束了，侵蝕體。"},"stage":{"bg":"COUNTRYROAD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아버지의 의지가 함께하는 이상, 나는 절대 너에게 굴복하지 않으니까.","JPN":"お父さんの思いが、私を支えてくれるなら。私は絶対あなたに屈しない。","ENG":"As long as I have my father's will with me, I will never surrender to you.","TWN":"只要爸爸的意志與我同在，我就不會向你屈服！"},"stage":{"bg":"COUNTRYROAD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"narration","speaker":null,"text":{"KOREA":"난 지금이라도 주저앉고 싶어. 난 나약하고, 죽음이 두렵고, 카운터도 아니니까.","JPN":"今すぐこの場でうずくまってしまいたい。私は弱気で死ぬことも怖いしカウンターでもないから。","ENG":"All I want to do right now is give up. I'm weak, I'm afraid of dying, and also not a Counter.","TWN":"雖然我現在就想放棄。我一直是個很軟弱，很怕死的人……而且我也並不是制裁者。"},"stage":{"bg":"COUNTRYROAD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_ASHA_IN_TRAILER_1"},{"id":"L41_1","type":"narration","speaker":null,"text":{"KOREA":"하지만…… 나는 일어서야 해.","JPN":"でも……私は立ち上がらなければならない。","ENG":"But... I must get back on my feet.","TWN":"但是……我必須站起來。"},"stage":{"bg":"COUNTRYROAD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_ASHA_IN_TRAILER_2"},{"id":"L42_1","type":"narration","speaker":null,"text":{"KOREA":"아버지라면, 분명 이러셨을 테니까.","JPN":"お父さんなら、きっとそうしてたはずだから。","ENG":"Because my father would've done the same.","TWN":"如果是爸爸的話，他肯定也會這麼做。"},"stage":{"bg":"COUNTRYROAD","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_ICE","voice":"AB_UI_UNIT_VOICE_OPR_ASHA_IN_TRAILER_3"},{"id":"L46_1","type":"narration","speaker":null,"text":{"KOREA":"진실을 받아들였으니, 더는 과거에 매달려 있을 수 없어.","JPN":"真実を受け入れたから、もう過去に縛られているわけにはいかないよ。","ENG":"I have accepted the truth, so I can't hang on to the past anymore.","TWN":"既然已經接受真相，就不能再糾結於過去。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_ASHA_IN_TRAILER_4"},{"id":"L47_1","type":"narration","speaker":null,"text":{"KOREA":"아버지는 모두를 위해 목숨을 바쳤어. 그러니 나도 이곳에서 멈춰선 안 돼.","JPN":"お父さんはみんなのために命を捧げた。だから、私もここに立ち止まっていちゃダメ。","ENG":"He sacrificed his life for everyone. So, I must also not stop here.","TWN":"爸爸為所有人獻出性命，所以我也不能在這裡停下。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_ASHA_IN_TRAILER_5"},{"id":"L48_1","type":"narration","speaker":null,"text":{"KOREA":"그것이…… 아버지, 그리고 내가 앞으로 나아가는 방법이니까.","JPN":"それが……お父さんと私が、前へ進むために必要なことだから。","ENG":"That is... the way my father and I will move forward.","TWN":"因為那是……爸爸，以及我前進的方式。"},"stage":{"bg":"MIND","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_ASHA_IN_TRAILER_6"}]`);export{e as default};